// CHECK-NEXT:    [[TMP3:%.*]] = load <16 x float>, ptr [[A]], align 4
// CHECK-NEXT:    [[TMP4:%.*]] = load <16 x float>, ptr [[B]], align 4
// CHECK-NEXT:    store <16 x float> [[TMP3]], ptr [[TMP1]], align 64
// CHECK-NEXT:    store <16 x float> [[TMP4]], ptr [[TMP0]], align 64
// CHECK-NEXT:    call void @ripple_ret_t16x16f32_t1x16f32_t16f32_externf(ptr nonnull [[TMP2]], ptr nonnull [[TMP1]], ptr nonnull [[TMP0]])
// CHECK-NEXT:    [[TMP5:%.*]] = load <256 x float>, ptr [[TMP2]], align 1024
// CHECK-NEXT:    store <256 x float> [[TMP5]], ptr [[C]], align 4
// CHECK-NEXT:    ret void
//
void test(float *restrict A, float *restrict B, float *restrict C) {
  ripple_block_t BS = ripple_set_block_shape(0, TILE_SIZE, TILE_SIZE);
  size_t v0 = ripple_id(BS, 0);
  size_t v1 = ripple_id(BS, 1);
  size_t v2 = v0 + ripple_get_block_size(BS, 0) * v1;
  C[v2] = externf(A[v1], B[v0]);
}

